class Solution(object):
    def leafSimilar(self, root1, root2):
        def get_leaves(node):
            if not node:
                return []
            if not node.left and not node.right:
                return [node.val]
            return get_leaves(node.left) + get_leaves(node.right)
        return get_leaves(root1) == get_leaves(root2)
